    // max 5 subdomain labels + 1 TLD; TLD must be alpha-only (no punycode/numeric)
    Type.String({pattern: '^([a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?[.]){1,5}[a-zA-Z]{2,}$'})
